// A real oscillating water droplet (Rayleigh–Lamb modes). Each spherical-
// harmonic surface mode l has natural frequency ω_l² ∝ l(l-1)(l+2) and viscous
// damping γ_l ∝ (l-1)(2l+1). We integrate 12 mode ODEs (l=2: 5 modes, l=3: 7)
// and hand their amplitudes to the shader, which rebuilds the surface from the
// SH basis. A poke injects energy into the modes; they ring at their true
// frequencies and interfere as they decay. This is the physics, not a fake.
try {
  const wd = sim.worldData
  const N = 12
  // per-mode natural frequency² and damping. l for modes 0..4 = 2, modes 5..11 = 3.
  if (!wd.__dp) {
    const w2 = 5.2                       // base ω² for l=2 (tunable stiffness)
    const g2 = 0.30                      // base damping for l=2
    const a = new Array(N).fill(0), v = new Array(N).fill(0)
    const om2 = [], gam = []
    for (let i = 0; i < N; i++) {
      const l = i < 5 ? 2 : 3
      om2.push(w2 * (l * (l - 1) * (l + 2)) / 8)      // Lamb: l(l-1)(l+2), normalized to l=2
      gam.push(g2 * ((l - 1) * (2 * l + 1)) / 5)      // (l-1)(2l+1), normalized to l=2
    }
    wd.__dp = { a, v, om2, gam, e: 0, lx: 256, ly: 256, mn: 0, sx: 0, sy: 0 }
    // a gentle initial deformation so it's alive on load
    for (let i = 0; i < N; i++) wd.__dp.v[i] = Math.sin(i * 12.9) * 0.12
  }
  const D = wd.__dp
  const pdt = Math.min(dt, 0.033)

  // CLICK — an impulsive poke: energy floods the low modes most (as a real
  // impact does), with a random spatial signature so no two pokes ring alike.
  const mn = wd.mouse_down_n || 0
  if (mn !== D.mn) {
    D.mn = mn
    for (let i = 0; i < N; i++) {
      const l = i < 5 ? 2 : 3
      const bias = l === 2 ? 1.0 : 0.5
      D.v[i] += (Math.random() * 2 - 1) * 6.5 * bias
    }
    wd.__play_sound = [
      { frequency: 120, duration: 0.28, volume: 0.4, type: 'sine' },
      { frequency: 180, duration: 0.18, volume: 0.22, type: 'triangle' }
    ]
  }

  // cursor motion stirs the cabin — a light, continuous drive into the l=2 modes
  const mx = wd.mouse_x, my = wd.mouse_y
  if (typeof mx === 'number') {
    const speed = Math.abs(mx - D.lx) + Math.abs(my - D.ly)
    D.lx = mx; D.ly = my
    const drive = Math.min(speed * 0.004, 0.5)
    D.v[0] += drive * ((mx / 512) - 0.5) * 2
    D.v[4] += drive * ((my / 512) - 0.5) * 2
    D.sx += (((mx / 512) - 0.5) * 1.4 - D.sx) * Math.min(1, pdt * 0.8)
    D.sy += ((0.5 - (my / 512)) * 0.85 - D.sy) * Math.min(1, pdt * 0.8)
  }

  // integrate every mode: ä = -ω²a - 2γȧ  (semi-implicit, stable)
  let energy = 0
  for (let i = 0; i < N; i++) {
    const acc = -D.om2[i] * D.a[i] - 2 * D.gam[i] * D.v[i]
    D.v[i] += acc * pdt
    D.a[i] += D.v[i] * pdt
    energy += Math.abs(D.a[i])
  }
  D.e = energy

  // publish: [energy, swayX, swayY, 0..., a0..a11 at 16..27]
  const U = new Array(28).fill(0)
  U[0] = Math.min(energy * 1.5, 2.0)
  U[1] = D.sx; U[2] = D.sy
  for (let i = 0; i < N; i++) U[16 + i] = D.a[i]
  wd.gpuUniforms = U
} catch (e) { /* keep the sim alive */ }

